"""
MKT Original Commentary — 2 Chronicles chapters 6–8
Run: python3 scripts/zc-original-2chronicles-6-8.py

Ch 6: Solomon's dedicatory prayer — the longest prayer in the OT
  - v1: H6205 ʿārafel (thick darkness) — divine hiddenness
  - v6: Deuteronomic Name theology — lišmî (for my name) not physical indwelling
  - v14: incomparability formula + bĕrît/ḥesed covenant-love pair
  - v18: hāʾumnām (truly/in very deed) + H120 ʾādām (human in earthly frailty)
  - v30: kî ʾattāh lᵉḇadᵉḵā yāḏaʿtā — divine omniscience absolute formula
  - v36: kî ʾên ʾādām ʾăšer lōʾ yeḥeṭāʾ — universal sinfulness
  - v41: Ps 132:8 quoted + H4496 mĕnûḥāh (resting place)
  - v42: H4899 mᵉšîḥeḵā (your anointed one) — messianic title

Ch 7: YHWH's response — fire, glory, the covenant answer
  - v1: H3519 kāḇôḏ (glory) + H784 ʾēš (fire) — divine acceptance pattern (cf. Lev 9:24)
  - v6: kî lĕʿôlām ḥasdô — the liturgical refrain from Ps 136
  - v14: four verbs — kānaʿ (humble/subdue Niphal), pālal (Hithpael pray), bāqaš (seek), šûḇ (turn/return)
  - v14: three divine responses — šāmaʿ (hear), sālaḥ (forgive), rāpāʾ (heal)
  - v16: ûpānāy wĕlibbî — my eyes and my heart — the personal divine attentiveness formula

Ch 8: Solomon's building work completes
  - v5-6: fortified cities; the mas (corvée) system
  - v11: Pharaoh's daughter relocated because of the holiness of David's spaces
  - v13-14: the three festivals; mišmĕrôT (Levitical divisions)
  - v16: H3559 kûn + H3615 kālāh — prepared and finished

NOTE: v7:14 already present; script will skip it via merge_comm.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "6": {
    "1": "<p><strong>ʿārafel</strong> (H6205) — thick/murky darkness — is the word for the dark cloud of divine presence (Exod 20:21: &lsquo;Moses drew near to the thick darkness where God was&rsquo;; Deut 4:11; 5:22; Ps 18:9; 97:2). Solomon&rsquo;s opening citation of YHWH&rsquo;s word is not from a known Torah text but recalls the Sinai cloud-theology: the God who is unapproachably holy (darkness) is nevertheless the God whose glory visibly descends (fire, cloud). The verse sets up the tension the prayer will explore: a transcendent God who pledges to dwell in one house.</p>",
    "2": "<p><strong>bêt zĕbûl</strong> — an exalted house; <em>zĕbûl</em> (H2073) means height/lofty dwelling. The word appears in the divine title <em>baal zĕbûl</em> (lord of the high house). Solomon uses elevated royal vocabulary to describe the temple, then immediately (v18) asks whether any building can contain the God of heaven. The tension is deliberate: the house is maximally exalted (<em>zĕbûl</em>) yet infinitely inadequate. <strong>lĕšibtᵉḵā lĕʿôlāmîm</strong> (a place for you to dwell in forever) — <em>lĕʿôlāmîm</em> is an intensified plural of eternity; Solomon prays that this house be a permanent divine address.</p>",
    "3": "<p>Solomon <strong>pānāh</strong> (turned, H6437) from facing the altar to face the assembly — a significant liturgical pivot. The verb marks a change of audience: Solomon has been directing his hands toward the altar (v12); now he turns to bless the people. <strong>yᵉḇāreḵ</strong> — Piel of <em>bāraḵ</em> (bless) — the Piel is the intensive/causative blessing form, the word used for the Aaronic blessing (Num 6:24-26). Solomon assumes a quasi-priestly role as the king who blesses the covenant assembly.</p>",
    "4": "<p><strong>bāraḵ</strong> + <strong>millēʾ</strong> (has fulfilled) — the primary theological claim of the speech: YHWH&rsquo;s word (<em>peh</em>, mouth) has been matched by his deeds (<em>yādô</em>, hand). The mouth-hand correspondence is a signature of divine faithfulness: YHWH does not merely speak; what his mouth declares his hand performs (Num 23:19: &lsquo;God is not a man, that he should lie... Has he spoken, and will he not do it?&rsquo;). The perfect tense of <em>millēʾ</em> (has fulfilled) marks the promise as now complete.</p>",
    "5": "<p>The Chronicler emphasizes that YHWH chose <strong>lōʾ-bāḥartî</strong> (I did not choose) any city or any man until David — the negative formulation before the positive choice heightens the sovereignty of election. <em>bāḥar</em> (H977, to choose/elect) is the election vocabulary used throughout Deuteronomy for YHWH&rsquo;s choice of Israel (Deut 7:6) and later of Jerusalem (Deut 12:5). The choice of Jerusalem and David are presented as simultaneous acts of divine will.</p>",
    "6": "<p><strong>lišmî</strong> (for my name) — the Deuteronomic Name theology is explicit: Jerusalem was chosen for YHWH&rsquo;s name (<em>šēm</em>) to dwell there, not YHWH himself in spatial totality. The distinction is crucial: <em>šēm</em> theology means God&rsquo;s authority, revelation, and representational presence are located at the temple while his transcendent being remains everywhere. This prevents crude localization while affirming genuine divine engagement at a specific earthly place. David was chosen as <em>lĭhyôt nāgîḏ</em> (to be ruler/prince) — <em>nāgîḏ</em> rather than <em>melek</em> (king) subtly emphasizes David&rsquo;s servant-leadership role.</p>",
    "7": "<p><strong>hayāh ʿim lĕḇāḇ</strong> (it was with the heart of) — the idiom means &lsquo;it was David&rsquo;s intention/desire.&rsquo; The Chronicler is intensely interested in the <em>lēḇāḇ</em> (heart) as the seat of intention. David&rsquo;s desire to build the temple was in his <em>lēḇāḇ</em> even if not realized — YHWH honored the intention. This will become a major Chronicler theme: the heart&rsquo;s disposition toward God matters as much as external acts (1 Chr 28:9; 29:17; 2 Chr 25:2: &lsquo;but not with a whole heart&rsquo;).</p>",
    "8": "<p><strong>hĕṭîḇôtā</strong> — Hiphil perfect of <em>yāṭaḇ</em> (to do well/be good) — &lsquo;you did well.&rsquo; YHWH commends David&rsquo;s intention: the desire to build for YHWH&rsquo;s name was praiseworthy even though David was not the appointed builder. This distinguishes motivation (commendable) from execution (divinely redirected). The pattern — good intention, divine redirection, honoring the intention — appears repeatedly: Moses desired to enter Canaan (denied, yet honored); Josiah wanted to restore worship (accepted, though partial).</p>",
    "9": "<p><strong>bĕnᵉḵā haYYôṣēʾ mimMēʿêḵā</strong> (your son who comes from your own loins) — the biological specificity of the Davidic succession. <em>mēʿeh</em> (entrails/womb, H4578) is used of offspring from one&rsquo;s body. The oracle distinguishes between David&rsquo;s general descendants and the specific son <em>hûʾ-yiḇneh lišmî</em> (he himself will build for my name) — the emphatic pronoun <em>hûʾ</em> marks Solomon as the definitively appointed builder, not merely a successor.</p>",
    "10": "<p><strong>waYYāqem YHWH ʾeT-dᵉḇārô</strong> (the LORD has kept/established his word) — <em>qûm</em> in the Hiphil means to make something stand firm, to establish, to fulfill a word given. The same root <em>qûm</em> appears in <em>qûmāh</em> (v41: arise!) addressed to YHWH. Solomon describes YHWH&rsquo;s word as something that has been made to stand — faithfulness as structural firmness. <strong>ʾaqqûm taḥaT dāwîḏ</strong> (I rose up in the place of David) — the succession language uses the same root <em>qûm</em>, creating a wordplay: the son who rose up (qûm) fulfills the word that YHWH caused to rise up (Hiphil qûm).</p>",
    "11": "<p><strong>ʾărôn bᵉrît YHWH</strong> — the ark of the covenant of YHWH. The <em>ʾārôn</em> (ark) is the physical symbol of the covenant, the container of the tablets (H3778 lûḥôT haḇᵉrît). Its placement in the temple&rsquo;s inner sanctuary completes the Davidic temple project: the ark has come home. The Chronicler stresses that the ark contains the <em>bᵉrît</em> (covenant) — the temple&rsquo;s legitimacy rests on housing the covenant document, making it a covenant-house rather than merely a royal religious center.</p>",
    "12": "<p>Solomon stood <strong>lipnê mizbaḥ YHWH</strong> (before the altar of YHWH) and stretched out his hands (<em>waYYiprōś kaPPāyw</em>). <em>prāś</em> (spread/stretch out) + <em>kap</em> (palm of hand) is the standard OT posture for petition prayer (Ps 28:2; 44:20; 88:9; Isa 1:15: &lsquo;when you spread out your hands...&rsquo;). The posture expresses openness and receptiveness, the opposite of the clenched fist. Solomon&rsquo;s prayer posture before the altar — not behind it as a priest — positions him as intercessor between the people and YHWH.</p>",
    "13": "<p>The bronze <strong>kiyyôr</strong> (platform/basin) — actually <em>kiYYôr</em> (H3595) means a portable cooking-pot or basin, here used for a raised platform. This is unique to Chronicles; Samuel-Kings does not mention it. Solomon knelt (<em>yiḵraʿ ʿal birKāyw</em>, knelt on his knees) and spread his hands toward heaven — two postures combined: prostration before YHWH (knees) and petition upward (hands toward heaven). The combination of humility (down) and petition (up) captures the paradox of prayer: addressing the transcendent God from a posture of creaturely submission.</p>",
    "14": "<p><strong>ʾên kāmôḵā ʾĕlōhîm</strong> (there is no God like you) — the incomparability formula used throughout the OT (Exod 15:11; Ps 86:8; Isa 40:25). It is not a denial of other gods&rsquo; existence but an affirmation of YHWH&rsquo;s incomparable superiority. <strong>bĕrît wĕḥesed</strong> — the pair &lsquo;covenant and steadfast love&rsquo; — <em>bĕrît</em> (H1285) is the formal covenant structure; <em>ḥesed</em> (H2617) is the relational quality of loyal-love within the covenant. The two together describe YHWH as both structurally faithful (covenant) and relationally warm (ḥesed). <strong>bĕkol-lēḇāḇām</strong> (with all their heart) — the Deuteronomic whole-heart devotion that conditions covenant blessing.</p>",
    "15": "<p><strong>ûḇᵉyāḏᵉḵā millēʾtāh</strong> (and with your hand you have fulfilled it) — the mouth-hand correspondence repeated from v4 in personal address: what YHWH spoke (<em>bᵉpîḵā</em>) he fulfilled (<em>bᵉyāḏᵉḵā</em>). The day (haYYôm hazZeh) marking the fulfillment makes the dedication moment theologically significant — Solomon is at the hinge-point between promise and fulfillment. The perfect tense of both verbs (<em>dibbartā</em>, you spoke; <em>millēʾtā</em>, you fulfilled) frames the entire dedication as a covenant-fulfillment event.</p>",
    "16": "<p><strong>lōʾ-yikkāreT lᵉḵā ʾîš miLPāNAY</strong> (there will not be cut off from you a man from before me) — the Davidic succession promise in its full form. <em>kārat</em> (H3772, to cut off) appears in negative: YHWH promises not to cut off the Davidic line. The idiom <em>miLPāNAY</em> (from before me, from my presence) means &lsquo;serving in my presence&rsquo; — the king who reigns is understood to reign in YHWH&rsquo;s presence, as his representative. The conditional clause: <em>raq ʾim-yišmᵉrû bānêḵā ʾeT-darKāM</em> (only if your sons guard their way) — the Mosaic condition remains.</p>",
    "17": "<p><strong>yēʾāmen dᵉḇāreḵā</strong> (may your word stand firm/be verified) — <em>ʾāman</em> (H539) in the Niphal means to be confirmed, proved reliable. The same root gives us <em>ʾāmēn</em> (so be it/truly). Solomon&rsquo;s petition has the character of affirming what YHWH has already said: &lsquo;may your word prove itself true.&rsquo; This is not doubt but the prayer-form of faith: holding YHWH to his own commitments. The prayer for verification of the word is the most basic form of covenant-prayer.</p>",
    "18": "<p><strong>hāʾumnām yēšēḇ ʾĕlōhîm ʾeT-hāʾādām ʿal-hāʾāreṣ</strong> — &lsquo;will God truly dwell with human beings on the earth?&rsquo; The particle <strong>hāʾumnām</strong> (H552, truly/in very deed) marks a rhetorical question that expects a negative answer — no, obviously God cannot be contained. <strong>hāʾādām</strong> uses the generic H120 (<em>ʾādām</em>), humanity in its earthly creatureliness. <strong>hinnēh haššāmayim ûšĕmê haššāmayim lōʾ yᵉḵalkᵉlûḵā</strong> — the double heaven (&lsquo;heavens and the heaven of heavens&rsquo;) cannot contain YHWH — the spatial hyperbole establishes absolute divine transcendence before the prayer petitions for divine immanence. The tension between vv18 and 40-42 (where Solomon asks YHWH to open his eyes toward this house) is the theological heart of the prayer.</p>",
    "19": "<p><strong>tᵉpillāh</strong> (H8605, prayer) + <strong>tᵉḥinnāh</strong> (H8467, supplication/plea for mercy) — the pair appears repeatedly in this chapter (vv20, 24, 25, 29, 35, 39). <em>Tᵉḥinnāh</em> derives from <em>ḥānan</em> (grace/favor) — it is a plea addressed to one in a superior position, requesting favor not owed. Solomon&rsquo;s petition that YHWH attend to &lsquo;the cry and the prayer&rsquo; (<em>ʾel-haRinnāh wĕʾel haT tᵉpillāh</em>) — <em>rinnāh</em> (H7440) means a shout, a ringing cry — combines joyful proclamation with formal petition.</p>",
    "20": "<p><strong>lihyôt ʿênêḵā pĕtûḥôT</strong> (may your eyes be open) — <em>pāqaḥ</em> (H6491, to open eyes) is used specifically of divine attention and human enlightenment. The petition asks that YHWH&rsquo;s eyes (<em>ʿênayim</em>) be permanently directed toward the temple. <strong>lamMāqôm ʾăšer ʾāmartā lāśûm šĕmeḵā šām</strong> — the place where YHWH said he would put his name — <em>śûm šēm</em> (place the name) is the standard Deuteronomic idiom for divine election of a place. The temple is defined entirely by the divine name-placement, not by its physical grandeur.</p>",
    "21": "<p><strong>tiššᵉmaʿ miMMĕqôm šiḇtᵉḵā min-haššāmayim</strong> — hear from the place of your sitting-enthroned from the heavens. <em>Šēḇet</em> (H3427, dwell/sit/be enthroned) describes YHWH as one who sits enthroned in heaven, not locally present in the temple — the temple is where prayer is directed, not where God physically resides. <strong>wĕsālaḥTā</strong> (and forgive) — the Qal perfect used as a jussive or expected consequence. The three-part structure of Solomon&rsquo;s petition-answers: <em>šāmaʿ</em> (hear from heaven) → <em>sālaḥ</em> (forgive) → result (restoration or justice). This structure repeats in all seven cases.</p>",
    "22": "<p>The seven petition cases begin. Case 1: <strong>ʾāšar neʾĕšam lᵉrēʿēhû</strong> (when someone sins against their neighbor). <em>ʾāšam</em> (H816, to be guilty/incur guilt) is the guilt-offering root — the action brings objective guilt, not just subjective wrongdoing. <strong>wĕnāśāʾ ʾālāyw ʾālāh</strong> (and is required to take an oath) — <em>ʾālāh</em> (H423) is a sworn oath with built-in curse if violated. The case addresses judicial disputes resolved by oath-swearing at the altar — a recognized legal mechanism (Exod 22:11).</p>",
    "23": "<p><strong>wᵉšāphaṭTā ʾeT-ʿăḇāḏêḵā</strong> — and you will judge your servants. YHWH is petitioned not merely to observe but to actively judge: <em>hārāšāʿ</em> (to condemn the guilty, Hiphil of <em>rāšaʿ</em>) + <em>hāṣaDdîq</em> (to vindicate the righteous, Hiphil of <em>ṣādaQ</em>). Both are legal declarations — the Hiphil of <em>ṣādaQ</em> is the formal judicial act of declaring righteous/not guilty (cf. Deut 25:1; Prov 17:15). Solomon asks YHWH to be the ultimate court of appeal whose verdicts are genuinely just.</p>",
    "24": "<p>Case 2: military defeat — <strong>wᵉhinnāgēf ʿamᵉḵā yiśrāʾēl lipnê ʾôyēḇ</strong> (when your people Israel are defeated before an enemy). <em>nāgaP</em> (H5062, to strike/defeat) in the Niphal — to be struck, suffer military defeat. The cause: <em>kî yeḥeṭᵉʾû lāḵ</em> (because they sinned against you) — the Deuteronomic theology of defeat as covenant consequence (Deut 28:25). The restoration: <em>wᵉšāḇû</em> (they turn back) + <em>wĕhôdû ʾeT-šĕmeḵā</em> (and confess/acknowledge your name) — confession uses <em>yāḏāh</em> (H3034, Hiphil) which means both to confess/admit and to give thanks.</p>",
    "25": "<p><strong>wĕhēḇēʾTā ʾôtām ʾel-hāʾādāmāh</strong> — and bring them back to the land. The restoration of exiled people to their land is the promised outcome of faithful repentance — the Deuteronomic return pattern (Deut 30:3-5: &lsquo;YHWH your God will restore your fortunes and have compassion on you, gathering you again from all the peoples&rsquo;). This petition (case 2) anticipates the Babylonian exile and return by centuries — Solomon&rsquo;s prayer is calibrated to a history not yet fully written.</p>",
    "26": "<p>Case 3: drought — <strong>bĕhiʿāṣēr haššāmayim wĕlōʾ-yihyeh māṭār</strong> (when the sky is shut and there is no rain). <em>ʿāṣar</em> (H6113, to restrain/shut) in the Niphal — the sky being shut/held back is the reverse of the divine blessing of opened heavens (Gen 7:11; Deut 28:12). <em>māṭār</em> (rain) is a covenant gift — withheld as covenant discipline (Deut 28:24: &lsquo;YHWH will make the rain of your land dust&rsquo;). The petitioner&rsquo;s response: <em>wĕhitPaLLĕlû ʾel hamMāqôm hazZeh</em> (they pray toward this place) — the temple becomes the focal point of petition even when the sky itself seems closed.</p>",
    "27": "<p><strong>wĕhôrêTām ʾeT-hadDereḵ haṭṭôḇāh</strong> (teach them the good/right way to walk) — instruction (<em>yārāh</em>, H3384, the root of <em>tôrāh</em>) as part of the divine response to repentance. YHWH&rsquo;s response to returning people is not merely to restore conditions but to provide instruction for the future. <em>wĕnātattāh māṭār ʿal-ʾarṣeḵā</em> (give rain on your land) — the rain that was withheld as discipline is now given as grace. The same land that suffered drought under judgment receives rain under restoration.</p>",
    "28": "<p>Case 4 opens a catalogue of disasters: <strong>rāʿāḇ kî-yihyeh bāʾāreṣ</strong> (famine), <strong>deber kî-yihyeh</strong> (plague/pestilence), <strong>šiddāpôn ûyērāqôn</strong> (blight and mildew/blasting and blighting — agricultural diseases), <strong>ʾarBeh wĕḥāsîl</strong> (locust and swarming locust/grasshopper). The list echoes the covenant curses of Deut 28:21-22,38-40: these are the consequences of covenant breaking, now brought under the scope of the temple&rsquo;s intercessory function.</p>",
    "29": "<p><strong>kol-tᵉpillāh kol-tᵉḥinnāh</strong> (every prayer, every supplication) — the universal scope: <em>kol</em> (all/every) before both prayer words extends the petition to every individual case, not merely the corporate situations previously described. <strong>ʾăšer yihyeh lᵉḵol-hāʾādām</strong> (whatever belongs to every person) — the switch to <em>hāʾādām</em> (human beings) rather than <em>ʿamᵉḵā</em> (your people) suggests inclusion of any human in distress. <em>maKKāTô ûmaḵʾôḇô</em> (their pain and their grief) — <em>maKKāh</em> (wound/blow) + <em>maḵʾôḇ</em> (pain/sorrow): each person&rsquo;s unique suffering is known to YHWH, not merely the corporate condition.</p>",
    "30": "<p><strong>kî ʾattāh lᵉḇadᵉḵā yāḏaʿtā</strong> (for you alone know) — the absolute divine omniscience formula. <em>lᵉḇadᵉḵā</em> (you alone, you exclusively) marks YHWH&rsquo;s heart-knowledge as uniquely divine: only he knows every heart. <em>yāḏaʿtā</em> (you have known, perfect tense) — the completed-action perfect for an eternal truth: YHWH has always known and continues to know. <strong>ʾeT-lĕḇaḇ bᵉnê hāʾādām</strong> — the hearts of the sons of humanity — <em>lēḇāḇ</em> (H3824, inner person/heart) is the seat of will, thought, and intention. What humans see externally, YHWH sees at the level of the heart.</p>",
    "31": "<p><strong>lᵉyirʾāh ʾôtᵉḵā</strong> (so that they may fear you) — <em>yārēʾ</em> (H3372, to fear/revere) is the practical outcome Solomon prays for. The purpose of YHWH&rsquo;s responsive justice is not punishment per se but the formation of the fear of God — the reverential recognition that YHWH sees and judges. <strong>lāleḵeT bidᵉrāḵêḵā</strong> (to walk in your ways) — covenant obedience expressed as <em>halāḵāh</em>-language (walking in ways): Hebrew moral life is directional movement, not merely rule-following. The fear of YHWH producing covenant walk is the Deuteronomic anthropological ideal.</p>",
    "32": "<p>Case 5: <strong>wĕgam ʾel-haNoḵrî ʾăšer lōʾ-mēʿamᵉḵā yiśrāʾēl hûʾ</strong> (and also for the foreigner who is not from your people Israel). <em>noḵrî</em> (H5236, foreigner/alien) — specifically a non-Israelite, distinct from <em>gēr</em> (resident alien living within Israel). Solomon petitions for the foreigner who comes <em>mēʾeres rĕḥôqāh</em> (from a distant land) because of YHWH&rsquo;s great name (<em>lĕšimᵉḵā haGGādôl</em>) and mighty arm (<em>yādᵉḵā haḥăzāqāh</em> + <em>zᵉrôʿăḵā haNNᵉṭûyāh</em>). The Exodus language (&lsquo;mighty hand and outstretched arm&rsquo;) applied to the Gentile&rsquo;s motive for prayer is remarkable — Gentiles are drawn to YHWH by the reputation of his saving acts for Israel.</p>",
    "33": "<p><strong>wĕʿāśîtā kol ʾăšer yiqrā ʾēlêḵā haNoḵrî</strong> — grant everything the foreigner calls upon you for. <em>qārāʾ</em> (call upon, appeal to) is the standard prayer verb. The petition&rsquo;s goal: <em>lĕmaʿan yēdĕʿû kol-ʿammê hāʾāreṣ ʾeT-šĕmeḵā</em> (so that all peoples of the earth may know your name). The universal dimension of Solomon&rsquo;s prayer is explicit: the temple is a place of prayer not for Israel alone but for all peoples (<em>kol-ʿammê hāʾāreṣ</em>). <em>yirʾûḵā</em> (to fear you) — the same goal as v31 — the fear of YHWH extending to all peoples through answered prayer at the temple.</p>",
    "34": "<p>Case 6: warfare — <strong>kî-yēṣēʾ ʿamᵉḵā lammilḥāmāh</strong> (when your people go out to war). The prayer directs toward <em>hāʿîr hazZōʾT</em> (this city) + <em>habBayiT</em> (this house) — the dual anchor point. <em>hadDereḵ ʾăšer tišlāḥēm</em> (wherever you send them) — YHWH as the one who sends the army; the troops go only where YHWH commissions. The petition appeals to YHWH as the divine warrior who supports those he sends.</p>",
    "35": "<p><strong>wĕšāmaʿtā min-haššāmayim ʾeT-tᵉpillātām wĕʾeT-tᵉḥinnātām</strong> — the standard hearing-petition formula. <strong>wĕʿāśîtā mišpāṭām</strong> (uphold their cause) — <em>mišpāṭ</em> (H4941) here means &lsquo;cause/right/legal case&rsquo; rather than merely &lsquo;judgment.&rsquo; YHWH is petitioned to act as the divine advocate who prosecutes on behalf of those he has sent. The pairing of <em>šāmaʿ</em> (hear) and <em>ʿāśāh mišpāṭ</em> (do justice/uphold cause) frames YHWH as judge-intercessor.</p>",
    "36": "<p><strong>kî ʾên ʾādām ʾăšer lōʾ yeḥeṭāʾ</strong> — for there is no human being who does not sin. This is one of the OT&rsquo;s clearest universal sinfulness statements. <em>ʾādām</em> (humanity) + <em>lōʾ yeḥeṭāʾ</em> (does not sin, imperfect of <em>ḥāṭāʾ</em>): the imperfect suggests habitual or potential action — no human consistently avoids sin. Case 7 (exile) is introduced: <em>wĕʾānaptā bām</em> (you are angry with them) — <em>ʾānap</em> (H0639/599, to be angry) — the divine anger as the theological cause of exile.</p>",
    "37": "<p><strong>wĕhiShîḇû ʾel-libbām</strong> (and they return it to their heart/they take it to heart) — <em>šûḇ</em> with <em>lēḇāḇ</em> describes an interior turning, a change of mind and will, not merely outward behavior change. <strong>ʾāšanû wĕhirShânû wĕrāšāʿnû</strong> — we have sinned, we have done wrong, we have acted wickedly — three escalating confession verbs. <em>ʾāšam</em> (incurred guilt), <em>hēraʿ</em> (done evil), <em>rāšaʿ</em> (acted wickedly) — the triple confession formula covers the full range of moral failure: objective guilt, practical wrongdoing, wicked character.</p>",
    "38": "<p><strong>wᵉšāḇû ʾēlêḵā bᵉkol-libbām ûḇᵉḵol-napšām</strong> — they return to you with all their heart and with all their soul. The <em>kol-lēḇāḇ</em> + <em>kol-nepeš</em> formula (whole heart + whole soul) is the Deuteronomic love-commandment vocabulary (Deut 6:5: &lsquo;love YHWH your God with all your heart, with all your soul, with all your strength&rsquo;). Repentance is nothing less than the restoration of the first-commandment wholeness. <em>darKām</em> (their way/direction of life) + <em>ʿîrᵉḵā</em> (your city) + <em>habBayiT</em> (this house) — the three-point geographical prayer anchor: land, city, temple.</p>",
    "39": "<p><strong>wĕšāmaʿtā min-haššāmayim mimmĕqôm šiḇtᵉḵā</strong> — hear from heaven, from the place of your sitting/enthronement. The spatial logic is now fully established: YHWH is enthroned in heaven (<em>šēḇet</em>, dwelling/enthroned); prayer rises from earth toward the temple; YHWH&rsquo;s response descends from heaven. The temple is the intersection-point, not YHWH&rsquo;s residence. <strong>wĕsālaḥtā lĕʿamᵉḵā</strong> — forgive your people: <em>sālaḥ</em> (H5545, to forgive/pardon) — this verb is used exclusively of YHWH in the OT; humans can pardon (<em>nāśāʾ</em>, lift/bear/forgive) but only YHWH <em>sālaḥ</em>. The divine prerogative of forgiveness is linguistically enforced.</p>",
    "40": "<p><strong>ʿattāh ʾĕlōhay yihyû-nāʾ ʿênêḵā pĕtûḥôT</strong> — now, my God, may your eyes be open. The concluding petition mirrors v20&rsquo;s opening request: the prayer is framed by this open-eyes image. <em>wĕʾoznêḵā qašûḇôT</em> (and your ears attentive) — <em>qāšaḇ</em> (H7181, to pay attention/listen carefully) in the Qal passive: ears that are set to attentive mode. The pairing of open eyes and attentive ears represents full divine awareness: nothing concerning this house escapes YHWH&rsquo;s perception.</p>",
    "41": "<p><strong>wᵉʿattāh qûmāh YHWH ʾĕlōhîm lᵉnûḥāteḵā</strong> — the invocation drawn from Ps 132:8 verbatim: &lsquo;arise, LORD God, to your resting place.&rsquo; <em>qûm</em> (arise, H6965) — the command to YHWH to move, to act. <em>mᵉnûḥāh</em> (H4496, resting place, rest) — the word describes the condition of settled, untroubled security. The ark of YHWH&rsquo;s power (<em>ʾărôn ʿuzzeḵā</em>) accompanies YHWH to his rest: the liturgical installation of the ark completes the journey that began when David brought it to Jerusalem. <strong>kôhănêḵā... yilbᵉšû yᵉšûʿāh</strong> (may your priests be clothed with salvation) — <em>lāḇaš</em> + <em>yᵉšûʿāh</em> is clothing-with-victory: priestly vestments as embodied declaration of divine saving power.</p>",
    "42": "<p><strong>ʾal-tāšēḇ pᵉnê mᵉšîḥeḵā</strong> — do not turn away the face of your anointed. <em>šûḇ pānîm</em> (turn away the face) means to reject a petitioner — the royal gesture of refusal (1 Kgs 2:16-17: &lsquo;do not turn away my face&rsquo;). <em>mᵉšîḥeḵā</em> (H4899, your anointed one) — from <em>māšaḥ</em> (to anoint), the technical term for the royal or priestly anointing that designates YHWH&rsquo;s chosen agent. Solomon applies the term to himself; the Psalms apply it to the ideal Davidic king (Ps 2:2; 18:50; 20:6; 89:38,51). The prayer closes with the messianic title — the anointed one&rsquo;s standing before YHWH depends on the covenant faithfulness (<em>ḥasdê dāwîḏ</em>, your steadfast love for David) rather than personal merit.</p>"
  },
  "7": {
    "1": "<p><strong>ʾēš yārĕḏāh meHaššāmayim</strong> (fire came down from the heavens) — the divine acceptance-by-fire pattern: the same event marks Lev 9:24 (tabernacle inauguration: &lsquo;fire came out from before YHWH&rsquo;), Elijah&rsquo;s Carmel sacrifice (1 Kgs 18:38), and David&rsquo;s threshing-floor offering (1 Chr 21:26). <strong>kāḇôḏ YHWH māleʾ ʾeT-habBāyit</strong> (the glory of YHWH filled the house) — <em>kāḇôḏ</em> (H3519, glory/weight/heaviness) is the term for YHWH&rsquo;s visible presence: the dense, luminous manifestation of divine being. The same filling occurred at the tabernacle&rsquo;s completion (Exod 40:34-35: &lsquo;the cloud covered the tent of meeting, and the glory of YHWH filled the tabernacle&rsquo;). The temple replaces the tabernacle as YHWH&rsquo;s authorized earthly address.</p>",
    "2": "<p><strong>lōʾ yāḵĕlû haKKōhănîm lāḇôʾ ʾel-bêT YHWH</strong> — the priests could not enter the LORD&rsquo;s house. The overwhelming divine presence physically prevents priestly service — not as judgment but as the excess of glory over human capacity. The same occurred at the tabernacle (Exod 40:35: &lsquo;Moses was not able to enter the tent of meeting because the cloud settled on it and the glory of YHWH filled the tabernacle&rsquo;). Divine glory is not merely a description but an encountered reality that imposes itself on physical space.</p>",
    "3": "<p><strong>wAYYiKRĕʿû ʾaPPAyim ʾarṣāh</strong> (bowed faces to the ground/pavement) — the prostration term <em>kāraʿ</em> (H3766, to bow the knee) + <em>ʾappayim</em> (face/nostrils to the ground). <em>Wayyishtaḥăwû</em> (and they worshiped/bowed down) — the Hishtaphel of <em>šāḥāh</em>: the intensive reflexive self-prostration form, the deepest posture of worship. The people&rsquo;s response to the glory is immediate, embodied, and communal. <strong>kî ṭôḇ kî lĕʿôlām ḥasdô</strong> — for he is good, for forever is his steadfast love — the liturgical refrain of Ps 136 (repeated 26×), which is also the refrain of the Levitical song in 1 Chr 16:34,41; 2 Chr 5:13.</p>",
    "4": "<p><strong>wĕhaMMelek wᵉḵol-hāʿām zōḇĕḥîm zeḇaḥ</strong> — the king and all the people offered sacrifices. <em>zāḇaḥ</em> (H2076, to sacrifice) and <em>zeḇaḥ</em> (H2077, sacrifice/offering) — the fellowship/peace offering (<em>šĕlāmîm</em>) in contrast to the wholly-consumed <em>ʿôlāh</em>: the <em>zeḇaḥ</em> was shared between God (fat portions burned), priests (specific portions), and worshiper (the rest). The king and all the people sharing in the sacrifice at the temple dedication is the communal meal that seals the covenant ratification.</p>",
    "5": "<p>Twenty-two thousand oxen and one hundred twenty thousand sheep — vast numbers marking the scale of the national dedication event. In ANE dedicatory contexts, rulers made large-scale sacrifices to demonstrate lavish devotion; Solomon&rsquo;s numbers are within the range of ancient Near Eastern royal inscriptions claiming thousands of animals sacrificed at temple dedications. The Chronicler preserves these figures to demonstrate the all-Israel scope of the dedication: this is not merely a royal ceremony but a national covenant-renewal.</p>",
    "6": "<p><strong>kî lĕʿôlām ḥasdô</strong> — the liturgical refrain repeated by the Levites with the instruments David had made. This is the <em>haLLēL</em> formula — the refrain of praise that accompanies sacrifice. The Levites with their cymbals, harps, and lyres (<em>mᵉṣiltayim kinnārôT ûnᵉḇālîm</em>) and the priests with their trumpets (<em>ḥăṣôṣrôT</em>) perform the full-orchestra expression of the covenant formula: <em>ḥesed</em> (steadfast love) that endures <em>lĕʿôlām</em> (forever) is the theological foundation of every act of worship.</p>",
    "7": "<p>The bronze altar was too small for the vast number of burnt offerings — Solomon <strong>qiddēš</strong> (consecrated, Piel of <em>qāḏaš</em>) the middle of the outer court for use. The Piel of <em>qāḏaš</em> is the technical term for declaring something holy/set apart for divine use. The improvised use of the outer court reflects the scale exceeding the permanent ritual infrastructure — the exceptional moment (temple dedication) requires extraordinary measures. The court&rsquo;s temporary consecration for sacrifice anticipates the theological principle that holiness can extend beyond fixed structures when the divine initiative demands it.</p>",
    "8": "<p><strong>mibBôʾ ḥămāT ʿad-naḥal miṣrāyim</strong> (from Lebo-hamath to the Wadi of Egypt) — the traditional north-to-south boundary of the ideal Israelite territory (Num 13:21; 34:8; 1 Kgs 8:65). The geographic formula marks this as an all-Israel gathering at the fullest territorial extent of the covenant land — the entire covenant community, from northern frontier to southern boundary, is present. This boundary formula signals the Solomonic golden age as the nearest historical approximation to the full covenant-land inheritance.</p>",
    "9": "<p><strong>waYYaʿăśû ḥănukkat hamMizBēaḥ šiḇʿat yāmîm wĕhehāḡ šiḇʿat yāmîm</strong> — seven days of altar dedication + seven days of the feast. The double seven-day festival before a one-day closing assembly totals fifteen days of celebration. <em>ḥănukkāh</em> (H2598, dedication/inauguration) — the same noun gives Hanukkah its name (the dedication of the rededicated temple in the Maccabean period). <em>ʿaṣeret</em> (closing assembly, H6116) — the solemn assembly on the eighth day mirrors the eighth-day <em>ʿaṣeret</em> of Sukkot/Shemini Atzeret in the liturgical calendar (Lev 23:36; Num 29:35).</p>",
    "10": "<p><strong>šiMĕḥîm wĕṭôḇê lēḇ ʿal-haṭṭôḇāh</strong> — joyful and glad of heart for the goodness. The triple joy vocabulary: <em>śāmēaḥ</em> (H8055, to rejoice/be glad), <em>ṭôḇ lēḇ</em> (good of heart), <em>haṭṭôḇāh</em> (the goodness) — all focusing on the quality of <em>ṭôḇ</em> (good). The people&rsquo;s joy is specifically &lsquo;for the goodness YHWH showed David, Solomon, and Israel his people&rsquo; — the joy is covenant-theologically grounded, not merely emotional. <em>lᵉdāwîḏ wĕlišlōmōh wĕlĕyiśrāʾēl ʿammô</em> — the three beneficiaries of covenant goodness named together.</p>",
    "11": "<p><strong>waYKallem</strong> (he finished/completed them) — Piel of <em>kālāh</em> (H3615), the completion verb. <em>kol-ʾăšer-bāʾ bĕlibBô laʿăśôt</em> — everything that entered his heart to do. The lēḇāḇ (heart) that initiated the temple project (Solomon&rsquo;s intent in v7) is now credited as the source of its completion. The Chronicler is careful to attribute the temple&rsquo;s completion to Solomon&rsquo;s God-given desire (<em>lāʿăśôT</em>, to do/make) rather than merely his administrative competence. <em>waYYaṣlaḥ</em> (he prospered/succeeded, Hiphil of <em>ṣālaḥ</em>) — the Chronicler&rsquo;s signature evaluation term (cf. 1 Chr 22:11,13; 29:23).</p>",
    "12": "<p><strong>waYYērāʾ YHWH ʾel-šlōmōh baLLāylāh</strong> — YHWH appeared to Solomon at night. The nighttime theophany echoes 1:7 (Gibeon) and 1 Kgs 3:5 (the dream at Gibeon). <em>rāʾāh</em> (H7200) in the Niphal — YHWH allowed himself to be seen/appeared. <strong>šāmaʿtî ʾeT-tᵉpillāteḵā</strong> (I have heard your prayer) — the simple perfect of hearing, confirming that Solomon&rsquo;s prayer in ch 6 was received. <strong>bāḥartî bammāqôm hazZeh lî lĕḇêT zāḇaḥ</strong> — I have chosen this place for myself as a house of sacrifice. <em>bāḥar</em> (H977, choose/elect) + <em>ḇayiT zāḇaḥ</em> (house of sacrifice) — YHWH names the temple explicitly as the designated sacrifice-place, not merely a dwelling.</p>",
    "13": "<p><strong>hēn ʾeʿṣōr</strong> (behold/if I close) — the first-person conditional introduced by <em>hēn</em> (behold/if) which sets up the three-part disaster series: <em>ʿāṣar haššāmayim</em> (close the sky from rain), <em>ṣiwwīT</em> (command locusts), <em>šalaḥtî</em> (send plague). The three disasters — drought, locust, plague — mirror the plagues of Egypt (reversed: Egypt&rsquo;s plagues were judgment on Gentiles; here they&rsquo;re discipline for Israel) and the Deuteronomic curse catalogue. YHWH speaks in first-person ownership of these disasters: he is not absent but actively disciplining through natural processes.</p>",
    "14": "<p>The famous verse. <strong>yiKKānĕʿû</strong> — Niphal of <em>kānaʿ</em> (H3665, to humble, subdue, bring low). The Niphal is reflexive: they humble themselves. <em>kānaʿ</em> carries the image of being brought low/subdued that YHWH did to enemies — the same humbling now applied voluntarily to oneself. <strong>yitPaLlĕlû</strong> — Hithpael of <em>pālal</em> (H6419, to pray) — the Hithpael is reflexive-intensive: to pray involves a self-evaluative activity, intercession with self-examination. <strong>yᵉḇaqqĕšû pānāy</strong> (seek my face) — <em>bāqaš</em> (H1245, active seeking/quest) + <em>pānîm</em> (face) — seeking the personal encounter with YHWH, not merely information from him. <strong>yāšûḇû midDarᵉkêhem haRāʿîm</strong> — <em>šûḇ</em> (H7725, return/repent) is the cardinal Hebrew repentance verb. The four verbs together describe the complete repentance movement: posture (humble), prayer (Hithpael pray), orientation (seek face), direction (turn from evil). YHWH&rsquo;s three responses: <em>ʾešmaʿ</em> (hear), <em>ʾeslaḥ</em> (forgive — the exclusive divine prerogative), <em>ʾerPāʾ</em> (heal/repair) the land.</p>",
    "15": "<p><strong>ʿattāh ʿênāy yihyû pĕtûḥôT</strong> — now my eyes will be open. The perfect response to Solomon&rsquo;s closing petition (6:40: &lsquo;may your eyes be open and your ears attentive&rsquo;): YHWH mirrors Solomon&rsquo;s language exactly. <em>ûʾoznay qašûḇôT</em> (and my ears attentive/pricked up) — <em>qāšaḇ</em> (H7181, to be attentive, to give ear) in the Qal passive describes ears set on alert-mode. The divine response to prayer includes both visual attention (eyes open) and auditory attention (ears attentive) — the full sensory metaphor for divine awareness.</p>",
    "16": "<p><strong>wĕʿattāh bāḥartî wĕqiddaštî ʾeT-habBayiT hazZeh</strong> — I have chosen and consecrated this house. Both verbs in the perfect: the choice and consecration are complete divine acts. <em>qiddēš</em> (Piel of <em>qāḏaš</em>, consecrate) — making something exclusively YHWH&rsquo;s, set apart from ordinary use. <strong>lihyôT šĕmî šām lĕʿôlām</strong> (for my name to be there forever) — the eternity of divine name-presence at this house. <strong>ûpānay wĕlibbî yihyû šām kol-hayYāmîm</strong> — my eyes and my heart will be there all the days. <em>pānîm</em> (face/eyes, H6440) + <em>lēḇ</em> (heart, H3820) paired — the personal divine attentiveness: YHWH promises both oversight (<em>pānîm</em>) and care (<em>lēḇ</em>) directed at this house eternally.</p>",
    "17": "<p><strong>wᵉʾim tiTHalleḵ lĕpānay</strong> — if you walk before me. <em>hālak lĕpānay</em> (walk before me) is the patriarchal covenant language: YHWH said to Abraham &lsquo;walk before me and be blameless&rsquo; (Gen 17:1). <em>lĕpānay</em> (before my face) — in my presence, under my gaze. <strong>kaʾăšer hālaḵ dāwîḏ ʾāḇîḵā</strong> (as your father David walked) — David is the standard of covenant walking. The reference to David&rsquo;s walk (<em>halāḵāh</em>) establishes the benchmark for Solomonic and future Davidic kings: the question is always whether the current king walks as David did.</p>",
    "18": "<p><strong>wăhăqîmôTî ʾeT kissēʾ malkûTeḵā</strong> — I will establish the throne of your kingdom. <em>qûm</em> (Hiphil, H6965) — to make stand firm, to establish. The recurring <em>kûn/qûm</em> root throughout these chapters (v11: everything was established, <em>wAYĀŠeR</em>; 6:10: YHWH has kept, <em>waYYāqem</em>) now appears in the divine promise of dynastic establishment. <em>lōʾ-yikkāreT lᵉḵā ʾîš môšēl bĕyiśrāʾēl</em> — there will not be cut off from you a man ruling in Israel — the unconditional core of the Davidic covenant, here qualified by the conditional of v17-19: the condition is Solomon&rsquo;s walking before YHWH.</p>",
    "19": "<p><strong>wᵉʾim tāšûḇû ûʿăzaḇtem ḥuqqôtay</strong> — but if you turn away and abandon my statutes. The counter-condition is introduced with <em>ʾim</em> + future: the conditional nature of the covenant&rsquo;s blessings. <em>ʿāzaḇ</em> (H5800, to leave/forsake/abandon) is the covenant-disloyalty verb: forsaking YHWH, forsaking the commandments. <em>ûhalaḵtem</em> (and you go) + <em>lăʿăḇōḏ</em> (to serve) + <em>ʾĕlōhîm ʾăḥērîm</em> (other gods) — the forbidden alternative covenant loyalty. The trajectory of abandonment: first the statutes (behavioral), then the full defection to other gods (covenantal).</p>",
    "20": "<p><strong>wᵉnâšaštî ʾôtām meʿal ʾadmātî</strong> — I will uproot them from my land. <em>nāšaš</em> (H5423) or variant <em>nātaš</em> — to pull up/tear out, used for uprooting plants: the agricultural metaphor for exile. <em>ʾadmātî</em> (my land) — YHWH claims ownership of the land of Israel even while Israel inhabits it (Lev 25:23: &lsquo;the land is mine; you are strangers and sojourners with me&rsquo;). <strong>wĕhaBBayiT hazZeh ʾăšer qiddaštî lišmî ʾašlîk mēʿal pānāy</strong> — this house I consecrated for my name I will cast away from before my face — <em>šālaḵ</em> (throw/cast away) describes the same motion as abandonment: the house devoted to YHWH&rsquo;s name can be disowned if the covenant is broken.</p>",
    "21": "<p><strong>wĕhaBBayiT hazZeh yihyeh ʿelyôn</strong> — this house which was so exalted — <em>ʿelyôn</em> (H5945, high/exalted) — the very word that described the temple&rsquo;s architectural grandeur is now used sarcastically for its ruined state. <em>ʿôḇēr ʿālāyw</em> (everyone who passes by it) + <em>yiššōmēm</em> (will be appalled/desolated) — <em>šāmēm</em> (H8074, to be desolated/appalled/ruined) is the word used for the desolation of Jerusalem in Lamentations (Lam 1:4,16; 3:11). The temple&rsquo;s fall from highest magnificence to an object of appalled horror is the ultimate Deuteronomic reversal.</p>",
    "22": "<p><strong>ʿāzᵉḇû ʾeT-YHWH ʾĕlōhê ʾăḇôtêhem</strong> — they abandoned YHWH the God of their ancestors. The final divine answer to the question &lsquo;Why has YHWH done this?&rsquo; uses the same verb <em>ʿāzaḇ</em> (abandon) as v19&rsquo;s condition: they abandoned YHWH (<em>ʿāzᵉḇû</em>), so YHWH brought this evil upon them. The covenant principle of correspondence: forsaking YHWH results in YHWH forsaking them (cf. 2 Chr 15:2: &lsquo;if you abandon him, he will abandon you&rsquo;). <em>waYYaḥzîqû bĕʾēlōhîm ʾăḥērîm</em> — they clung to other gods — <em>ḥāzaq</em> (grasp, hold tightly) reveals that the problem was not passive drift but active attachment to alternatives.</p>"
  },
  "8": {
    "1": "<p>The twenty-year building summary — <strong>miqqēṣ ʿeśrîm šānāh</strong> (at the end of twenty years). <em>miqqēṣ</em> (H7093, from the end of) — the temporal hinge after which Solomon&rsquo;s administrative and territorial expansion begins. The twenty years divides neatly: seven years for the temple (1 Kgs 6:38) and thirteen years for the palace (1 Kgs 7:1). The Chronicler does not preserve these numbers here, focusing instead on the building&rsquo;s completion as a unified event.</p>",
    "2": "<p><strong>waYYiḇen šlōmōh ʾeT-hāʿārîm</strong> — Solomon rebuilt the towns Huram had given him. In 1 Kgs 9:10-13 the arrangement is reversed — Solomon gave Huram twenty cities, who found them unsatisfactory and called them &lsquo;Cabul.&rsquo; The Chronicler&rsquo;s version has Huram giving cities to Solomon. The divergence reflects either different source traditions or the Chronicler&rsquo;s ideological adjustment: a Solomon who receives from the Gentile king rather than gives away Israelite territory better fits the Chronicler&rsquo;s presentation of Solomon&rsquo;s imperial success.</p>",
    "3": "<p><strong>waYYēleḵ šlōmōh ḥămāT-ṣôḇāh</strong> — Solomon marched to Hamath-zobah and captured it. Hamath-zobah is the Aramean kingdom north of Damascus. This military action is unique to Chronicles; Samuel-Kings does not record it. The Chronicler may draw on a source otherwise lost. The verb <em>yālaḵ</em> (went/marched) with <em>waYYiLKaDâH</em> (and captured it) presents Solomon as not merely a builder but a military commander — the Solomonic empire extends to the northern frontier.</p>",
    "4": "<p><strong>waYYiḇen ʾeT-tadMōr bamMidBār</strong> — he built Tadmor in the desert. Tadmor is Palmyra, the famous desert oasis city in the Syrian desert. The Chronicler includes this as part of Solomon&rsquo;s store-city building programme in the far north. The building of store cities (<em>ʿārê miSkenôT</em>) reflects the administrative infrastructure of the empire: food reserves, tax collection, and supply chains for military and trade purposes.</p>",
    "5": "<p><strong>waYYiḇen ʾeT-bêT-ḥôrôn hāʿelyônāh wĕʾeT-bêT-ḥôrôn haṭTaḥtônāh</strong> — Upper and Lower Beth-horon. Beth-horon was the key pass controlling the Shephelah-to-highlands route; both fortified by Solomon (<em>ʿārîm bĕṣûrôT</em>, fortified cities) with walls, gates, and bars (<em>ḥômâh dĕlātayim ûḇərîaḥ</em>). The same Beth-horon appeared in 7:24 as built by Sheerah. Solomon now fortifies what Ephraim&rsquo;s daughter had built — the administrative continuity of strategic locations across Israel&rsquo;s history.</p>",
    "6": "<p><strong>bāʿalāT</strong> (Baalath) — a Danite town (Josh 19:44; 1 Kgs 9:18). The store cities and chariot cities (<em>ʿārê hāreḵeḇ</em>) and cavalry cities (<em>ʿārê hapPārāšîm</em>) represent the infrastructure of Solomon&rsquo;s military power. <em>ʾēt kol-ḥēšeq šĕlōmōh</em> (everything Solomon desired/was pleased to build) — <em>ḥēšeq</em> (H2836, desire/pleasure) — the same root as the covenant-desire vocabulary (Deut 7:7: not because of your greatness did YHWH <em>ḥāšaq</em> to you). Solomon&rsquo;s building desires are limitless — in Lebanon, throughout his territory.</p>",
    "7": "<p>The non-Israelite peoples — <strong>haḥittî wĕhāʾĕmōrî wĕhapPĕrizzî wĕhaḥiWwî wĕhaYYĕḇûsî</strong> — the standard list of Canaan&rsquo;s pre-Israelite inhabitants. <em>ʾăšer lōʾ-mēyiśrāʾēl hēmmāh</em> (who were not from Israel) — the ethnic distinction between the forced labor pool and the Israelite population. These are the <em>nôter</em> (H3498, remainder/survivors) from the incomplete conquest — the peoples Israel failed to drive out who now serve the Solomonic state.</p>",
    "8": "<p><strong>waYYaʿălēm šĕlōmōh lĕmas</strong> — Solomon conscripted them as forced labor (<em>mas</em>, H4522). The <em>mas</em> system (corvée/tribute labor) was the standard ANE mechanism for mobilizing labor for large building projects — attested in Mesopotamian and Egyptian administrative texts. <em>ʿad-haYYôm hazZeh</em> (until this day) — a formulaic phrase indicating the information comes from a source contemporary with conditions the Chronicler knew had ended or changed.</p>",
    "9": "<p><strong>ûmibBĕnê yiśrāʾēl lōʾ-nātan šĕlōmōh ʿăḇādîm</strong> — Solomon did not make Israelites as slaves. <em>ʿeḇed</em> (H5650, slave/servant) — the distinction is fundamental: Israelites serve as <em>ʾanšê milḥāmāh</em> (warriors/soldiers), <em>śārê šālîšāyw</em> (officers), <em>śārê rĕḵeḇ</em> (chariot commanders), and <em>pārāšîm</em> (cavalry). The covenant people are free men in the military hierarchy; the non-Israelites are the labor pool. The same distinction the Exodus narrative established — Israel freed from Egyptian slave-labor (<em>mas</em>, Exod 1:11) — is now maintained within Solomon&rsquo;s empire.</p>",
    "10": "<p><strong>ʾēlleh śārê haNeṣṣāḇîm</strong> (these are the chief officers/overseers) — <em>niṣṣāḇ</em> (H5324, Niphal of <em>yāṣaḇ</em>, standing/stationed) — the officers stationed over the work. 250 chief officers in Chronicles vs. 550 in 1 Kgs 9:23 (a different accounting perhaps of the same or overlapping administrative tiers). The administrative numbers in Chronicles and Kings reflect different archival sources rather than editorial invention.</p>",
    "11": "<p><strong>waYYaʿal šlōmōh ʾeT-bat-parʿōh</strong> — Solomon moved Pharaoh&rsquo;s daughter. The reason given: <em>kî ʾāmar lōʾ-tēšēḇ ʾiššāh lî bĕbêT dāwîḏ melek-yiśrāʾēl</em> — &lsquo;my wife must not live in the house of David king of Israel, for the places are holy that the ark of YHWH has entered.&rsquo; The holiness principle: the ark&rsquo;s presence has consecrated David&rsquo;s city with a grade of holiness incompatible with the residence of a Gentile wife. <em>qāḏôš</em> (holy) places that the ark entered — spatial holiness extending beyond the sanctuary proper to the entire city of David.</p>",
    "12": "<p><strong>waYYaʿal šlōmōh ʿôlôT lîYHWH</strong> — Solomon offered burnt offerings. <em>ʿôlāh</em> (H5930, burnt offering/whole burnt offering) — entirely consumed on the altar, nothing returned to the offerer. The <em>ʿôlāh</em> is the offering of total devotion: the animal is wholly given to YHWH. <em>ʿal miZBaḥ YHWH ʾăšer bānāh lipnê hāʾûlām</em> (on the altar of YHWH that he built in front of the portico) — the exterior altar in front of the temple&rsquo;s vestibule (<em>ûlām</em>).</p>",
    "13": "<p><strong>ûḇidBar môšeh laSŠAbbātôT wĕlaḥŏdāšîm wĕlaMMôʿādôT šālôš pĕʿāmîm baSSānāh</strong> — the three annual pilgrimage festivals: <em>Ḥag hamMaṣṣôT</em> (Feast of Unleavened Bread/Passover), <em>Šāḇûôt</em> (Feast of Weeks/Pentecost), <em>Sukkôt</em> (Feast of Tabernacles). <em>môʿēḏ</em> (H4150, appointed time/season/festival) — the technical term for the liturgical calendar (Lev 23; Num 28-29). The festivals are characterized as according to <em>midBār môšeh</em> (the command of Moses) — Solomon&rsquo;s worship is explicitly Mosaic, grounded in the Torah calendar.</p>",
    "14": "<p><strong>waYYaʿămēd... mišmĕrôT haKKōhănîm</strong> — he appointed the priestly divisions (<em>mišmĕrôT</em>, H4931, watch/guard/division). The <em>mišmĕrôT</em> system — the rotating schedule of priestly divisions serving at the temple — was attributed to David (1 Chr 24:3-19). Solomon implements what David organized. The Levites are assigned to <em>lĕhaLLēL ûlĕšārēT negDed haKKōhănîm</em> (to praise and to minister before the priests) — the Levitical role as support-ministers to the priests, with their primary function being praise (<em>haLLēL</em>).</p>",
    "15": "<p><strong>lōʾ-sārû</strong> (they did not deviate) — the perfect obedience of priests and Levites to the king&rsquo;s commands (<em>miṣwat hamMelek</em>). <em>sûr</em> (H5493, to turn aside/deviate) is the verb of covenant-straying: its negation signals that the temple&rsquo;s inaugural liturgical order was faithfully maintained. The detail about the treasuries (<em>ʿal-hāʾôṣārôT</em>) confirms that financial administration followed the same disciplined structure as ritual service.</p>",
    "16": "<p><strong>waYYikkon kol-mĕlaʾḵet šĕlōmōh</strong> — all Solomon&rsquo;s work was made firm/established. <em>kûn</em> (H3559, Niphal: to be established/prepared/made ready) — the same root used for the established throne (2 Sam 7:16; 1 Chr 17:14). <em>mikYôm mûSad bêT YHWH wĕʿad-šallĕmô</em> (from the day the foundation of YHWH&rsquo;s house was laid until its completion) — <em>šālem</em> (H7999, to be complete/finished/at peace) — the completion verb that shares its root with <em>šālôm</em>: the house is at peace/complete. <em>waYYiSHlem bêT YHWH</em> (and the house of YHWH was finished) — the Piel of <em>šālem</em>: made complete, brought to full integrity.</p>",
    "17": "<p><strong>ʾāz hālaḵ šĕlōmōh lĕʿeṣyôn-geḇer wĕʾel-ʾêlôT</strong> — Solomon went to Ezion-geber and Eloth on the coast of the Red Sea. Ezion-geber (Tell el-Kheleifeh, at the head of the Gulf of Aqaba/Eilat) was Israel&rsquo;s Red Sea port. <em>ʾêlôT</em> (Elath/Eilat) is the ancient port city. The Solomonic maritime enterprise requires this access to the Red Sea routes — the trade network that brought the gold of Ophir.</p>",
    "18": "<p><strong>waYYišlaḥ-lô ḥûrām bĕyad-ʿăḇādāyw ʾŏniyyôT</strong> — Huram sent him ships crewed by his experienced sailors. <em>ʿăḇādāyw</em> (his servants/sailors) + <em>yôdĕʿê hayYām</em> (who knew/experienced the sea) — Phoenician maritime expertise supplementing the Israelite trade capacity. <em>wAYāḇōʾû ʾôPīrāh</em> (and they came to Ophir) — Ophir is the legendary gold source; its precise location is debated (East Africa, Arabia, or India). <em>ʾarBaʿ mēʾôT waḥămiSSîm kikkar zāhāḇ</em> (450 talents of gold — 1 Kgs 10:11 says 420; the variant reflects different archival traditions).</p>"
  }
}

def main():
    existing = load_comm('mkt-original', '2chronicles')
    merge_comm(existing, ORIGINAL)
    save_comm('mkt-original', '2chronicles', existing)
    v6 = len(ORIGINAL.get('6', {}))
    v7 = len(ORIGINAL.get('7', {}))
    v8 = len(ORIGINAL.get('8', {}))
    print(f'2Chronicles 6-8 mkt-original written ({v6} + {v7} + {v8} = {v6+v7+v8} verses).')

if __name__ == '__main__':
    main()
